class Solution {
    public int integerReplacement(int n) {
        long x = n;
        int res = 0;
        while (x > 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else if ((x & 1) == 1 && (x + 1) % 2 == 0 || x % 4 == 1) {
                x++;
            } else {
                x--;
            }
            res++;
        }
        return res;
    }
}
```

